/* ============================================================
   hooks/
   ============================================================ */
function useReducedMotion() {
  const [r, setR] = useState(false);
  useEffect(() => {
    const m = window.matchMedia("(prefers-reduced-motion: reduce)");
    setR(m.matches);
    const h = () => setR(m.matches);
    m.addEventListener?.("change", h);
    return () => m.removeEventListener?.("change", h);
  }, []);
  return r;
}
function useInView(threshold = 0.2) {
  const ref = useRef(null);
  const [seen, setSeen] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el || seen) return;
    const io = new IntersectionObserver(
      ([e]) => e.isIntersecting && (setSeen(true), io.disconnect()),
      { threshold }
    );
    io.observe(el);
    return () => io.disconnect();
  }, [seen, threshold]);
  return [ref, seen];
}
function useCountUp(value, run, duration = 400, delay = 0) {
  const [n, setN] = useState(0);
  useEffect(() => {
    if (!run) return;
    let raf, start;
    const t = setTimeout(() => {
      const tick = (ts) => {
        if (!start) start = ts;
        const p = Math.min((ts - start) / duration, 1);
        setN(Math.round(easeOutCubic(p) * value));
        if (p < 1) raf = requestAnimationFrame(tick);
      };
      raf = requestAnimationFrame(tick);
    }, delay);
    return () => {
      clearTimeout(t);
      cancelAnimationFrame(raf);
    };
  }, [run, value, duration, delay]);
  return n;
}

/* ============================================================
   typing primitives
   ============================================================ */
function Typewriter({ text, speed = 26, onDone }) {
  const reduced = useReducedMotion();
  const [len, setLen] = useState(reduced ? text.length : 0);
  const done = useRef(false);
  useEffect(() => {
    done.current = false;
    setLen(reduced ? text.length : 0);
  }, [text, reduced]);
  useEffect(() => {
    if (len >= text.length) {
      if (!done.current) {
        done.current = true;
        onDone && onDone();
      }
      return;
    }
    const id = setTimeout(() => setLen((l) => l + 1), speed);
    return () => clearTimeout(id);
  }, [len, text, speed, onDone]);
  return (
    <>
      {text.slice(0, len)}
      {len < text.length && <span className="caret">|</span>}
    </>
  );
}
function SubtitleCycler({ lines, hold = 850, speed = 26, onDone, style }) {
  const [idx, setIdx] = useState(0);
  const advance = useCallback(() => {
    const t = setTimeout(() => {
      setIdx((i) => {
        if (i + 1 >= lines.length) {
          onDone && onDone();
          return i;
        }
        return i + 1;
      });
    }, hold);
    return () => clearTimeout(t);
  }, [lines.length, hold, onDone]);
  return (
    <span style={style}>
      <Typewriter key={idx} text={lines[idx]} speed={speed} onDone={advance} />
    </span>
  );
}

