function PriceRow({ row, active, onDone, last, instant }) {
  const reduced = useReducedMotion();
  const rref = useRef(null);
  const cn = useCountUp(row.price, active && !instant, 400);
  const n = instant ? row.price : cn;
  const fired = useRef(false);
  useEffect(() => {
    if (instant) return;
    if (active && !fired.current) {
      fired.current = true;
      if (!reduced) rref.current?.scrollIntoView({ block: "center", behavior: "smooth" });
      const t = setTimeout(onDone, 440);
      return () => clearTimeout(t);
    }
  }, [active, onDone, reduced, instant]);
  const show = instant || active || n > 0;
  return (
    <div
      ref={rref}
      style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", padding: "12px 0", borderBottom: last ? "none" : "1px solid #F0F4EE", opacity: show ? 1 : 0.32, transform: show ? "translateX(0)" : "translateX(-6px)", transition: `all 300ms ${EASE}` }}
    >
      <div style={{ paddingRight: 12 }}>
        <div style={{ fontFamily: FONT, fontSize: 15.5, color: INK, fontWeight: 500 }}>{row.name}</div>
        <div style={{ fontFamily: FONT, fontSize: 12.5, color: "#9AA792", marginTop: 2 }}>{row.spec}</div>
      </div>
      <span style={{ fontFamily: FONT, fontSize: 15.5, fontWeight: 700, whiteSpace: "nowrap", color: show ? INK : "#B7C4AE", fontVariantNumeric: "tabular-nums" }}>{rp(n)}</span>
    </div>
  );
}

function CategoryCard({ cat, canStart, onFinish, instant }) {
  const [ref, seen] = useInView(0.18);
  const [rowIdx, setRowIdx] = useState(instant ? cat.rows.length : -1);
  const started = seen && canStart;
  useEffect(() => {
    if (!instant && started && rowIdx === -1) setRowIdx(0);
  }, [started, rowIdx, instant]);
  const subtotal = cat.rows.reduce((a, r) => a + r.price, 0);
  const allRowsDone = rowIdx >= cat.rows.length;
  const scn = useCountUp(subtotal, allRowsDone && !instant, 500);
  const subN = instant ? subtotal : scn;
  const fired = useRef(false);
  useEffect(() => {
    if (allRowsDone && !fired.current) {
      fired.current = true;
      if (instant) {
        onFinish();
      } else {
        const t = setTimeout(onFinish, 520);
        return () => clearTimeout(t);
      }
    }
  }, [allRowsDone, onFinish, instant]);
  return (
    <div ref={ref}>
      <Card style={{ marginBottom: 16 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 6 }}>
          <PopIcon>{cat.icon}</PopIcon>
          <h3 style={{ fontFamily: FONT, fontSize: 19, fontWeight: 800, color: INK, margin: 0 }}>{cat.title}</h3>
        </div>
        {cat.rows.map((row, i) => (
          <PriceRow key={row.name} row={row} active={rowIdx >= i} last={i === cat.rows.length - 1} instant={instant} onDone={() => setRowIdx((r) => (r === i ? i + 1 : r))} />
        ))}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 14, paddingTop: 14, borderTop: "2px dashed #E6EDDF" }}>
          <span style={{ fontFamily: FONT, fontSize: 13.5, fontWeight: 700, color: SUBT, letterSpacing: 0.4 }}>Subtotal</span>
          <span style={{ fontFamily: FONT, fontSize: 18, fontWeight: 800, color: GREEN_DARK, fontVariantNumeric: "tabular-nums" }}>{rp(subN)}</span>
        </div>
      </Card>
    </div>
  );
}

function StepBudget({ name, onNext, onBack, instant, onAnimated }) {
  const reduced = useReducedMotion();
  const [finished, setFinished] = useState(instant ? [true, true, true] : [false, false, false]);
  const [totalDone, setTotalDone] = useState(instant);
  const [ready, setReady] = useState(instant);
  const endRef = useRef(null);

  const markDone = useCallback((i) => {
    setFinished((f) => {
      if (f[i]) return f;
      const nx = [...f];
      nx[i] = true;
      return nx;
    });
  }, []);
  const allDone = finished.every(Boolean);
  const tcn = useCountUp(GRAND_TOTAL, allDone && !instant, 800);
  const totalN = instant ? GRAND_TOTAL : tcn;

  useEffect(() => {
    if (instant || !allDone) return;
    const t = setTimeout(() => {
      setTotalDone(true);
      // settle smoothly at the very bottom (total + button), no jump upward
      if (!reduced) {
        requestAnimationFrame(() =>
          window.scrollTo({ top: document.body.scrollHeight, behavior: "smooth" })
        );
      }
    }, 950);
    return () => clearTimeout(t);
  }, [allDone, reduced, instant]);

  useEffect(() => {
    if (ready && !instant) onAnimated && onAnimated();
  }, [ready, instant, onAnimated]);

  const onToastDone = useCallback(() => setReady(true), []);

  const stats = [
    ["72", "Lubang Tanam"],
    ["1.5 m²", "Area Tanam"],
    ["30–35", "Hari Panen"],
  ];

  return (
    <div style={{ minHeight: "100dvh", padding: "30px 22px 150px", background: `linear-gradient(180deg,${MINT_TOP},${MINT_BOT})` }}>
      <Stepper step={2} onBack={onBack} />
      <h1 style={{ fontFamily: FONT, fontSize: 30, fontWeight: 800, color: INK, margin: 0, letterSpacing: -0.4 }}>Hai, {name}! 👋</h1>
      <p style={{ fontFamily: FONT, fontSize: 15.5, color: SUBT, lineHeight: 1.55, marginTop: 12, marginBottom: 24 }}>
        Ini rincian biaya sistem hidroponik yang aku pakai.
      </p>

      <Card style={{ marginBottom: 28, background: "linear-gradient(180deg,#fff,#FAFDF4)" }} animate={false}>
        <div style={{ display: "flex", justifyContent: "space-between", textAlign: "center" }}>
          {stats.map(([big, small], i) => (
            <div key={i} style={{ flex: 1, position: "relative" }}>
              {i > 0 && <div style={{ position: "absolute", left: 0, top: 6, bottom: 6, width: 1, background: "#ECF1E6" }} />}
              <div style={{ fontFamily: FONT, fontSize: 25, fontWeight: 800, color: GREEN_DARK, lineHeight: 1.05, letterSpacing: -0.3 }}>{big}</div>
              <div style={{ fontFamily: FONT, fontSize: 12, color: SUBT, marginTop: 6 }}>{small}</div>
            </div>
          ))}
        </div>
      </Card>

      <h2 style={{ fontFamily: FONT, fontSize: 23, fontWeight: 800, color: INK, marginBottom: 18, letterSpacing: -0.3 }}>Rincian Biaya</h2>

      {BUDGET.map((cat, i) => (
        <CategoryCard key={cat.title} cat={cat} instant={instant} canStart={i === 0 ? true : finished[i - 1]} onFinish={() => markDone(i)} />
      ))}

      {/* TOTAL - orange base, white font */}
      <div style={{ marginTop: 8, background: `linear-gradient(135deg, ${ORANGE}, ${ORANGE2})`, borderRadius: 24, padding: "24px 24px", display: "flex", justifyContent: "space-between", alignItems: "center", boxShadow: "0 16px 34px rgba(255,81,31,0.36)" }}>
        <div>
          <div style={{ fontFamily: FONT, fontSize: 13, color: "rgba(255,255,255,0.9)", fontWeight: 600, letterSpacing: 0.6 }}>TOTAL INVESTASI</div>
          <div style={{ fontFamily: FONT, fontSize: 12, color: "rgba(255,255,255,0.75)", marginTop: 2 }}>Sistem lengkap</div>
        </div>
        <div style={{ fontFamily: FONT, fontSize: 29, fontWeight: 800, color: "#fff", fontVariantNumeric: "tabular-nums", letterSpacing: -0.3 }}>{rp(totalN)}</div>
      </div>

      <div ref={endRef} />

      {/* sticky CTA + purple toast */}
      <div style={{ position: "sticky", bottom: 0, marginLeft: -22, marginRight: -22, marginTop: 24, padding: "16px 22px calc(16px + env(safe-area-inset-bottom))", background: `linear-gradient(180deg, rgba(234,243,228,0) 0%, ${MINT_BOT} 34%)` }}>
        <div style={{ position: "relative" }}>
          {totalDone && (
            <div style={{ position: "absolute", left: 0, right: 0, bottom: "calc(100% + 12px)", display: "flex", justifyContent: "center", animation: `toastUp 380ms ${EASE} both` }}>
              <div style={{ position: "relative", background: PURPLE, color: "#fff", fontFamily: FONT, fontSize: 15, fontWeight: 600, padding: "13px 18px", borderRadius: 16, boxShadow: "0 12px 26px rgba(121,107,231,0.4)", maxWidth: "92%", textAlign: "center" }}>
                {instant ? "Tapi tenang…" : <SubtitleCycler lines={["Banyak ya investasinya…", "Tapi tenang…"]} hold={750} speed={30} onDone={onToastDone} />}
                <span style={{ position: "absolute", left: "50%", top: "100%", transform: "translateX(-50%)", width: 0, height: 0, borderLeft: "9px solid transparent", borderRight: "9px solid transparent", borderTop: `10px solid ${PURPLE}` }} />
              </div>
            </div>
          )}
          <Button disabled={!ready} onClick={onNext} pulse>
            Lanjutkan Kesimpulan
          </Button>
        </div>
      </div>
    </div>
  );
}

