/* ============================================================
   app/
   ============================================================ */
export default function App() {
  const [page, setPage] = useState(0);
  const [name, setName] = useState("");
  const budgetSeen = useRef(false); // animate budget only once, ever

  // disable browser scroll restoration once
  useEffect(() => {
    if (typeof history !== "undefined" && "scrollRestoration" in history) {
      history.scrollRestoration = "manual";
    }
  }, []);

  // on every page change: jump to top + tint the status bar to match the page
  useEffect(() => {
    const reset = () => window.scrollTo({ top: 0, left: 0, behavior: "auto" });
    reset();
    const r = requestAnimationFrame(reset);
    const t = setTimeout(reset, 60);

    const color = page === 0 ? GREEN_DARK : MINT_TOP;
    let meta = document.querySelector('meta[name="theme-color"]');
    if (!meta) {
      meta = document.createElement("meta");
      meta.setAttribute("name", "theme-color");
      document.head.appendChild(meta);
    }
    meta.setAttribute("content", color);
    // paint body/edges to match the page so there is no white seam or overscroll flash
    document.body.style.backgroundColor = color;

    return () => {
      cancelAnimationFrame(r);
      clearTimeout(t);
    };
  }, [page]);

  const go = (next, savedName) => {
    if (savedName) setName(savedName);
    setPage(next);
  };

  const pages = [
    <StepWelcome key="w" onNext={(n) => go(1, n)} />,
    <StepBudget key="b" name={name || "teman"} instant={budgetSeen.current} onAnimated={() => { budgetSeen.current = true; }} onNext={() => go(2)} onBack={() => go(0)} />,
    <StepSummary key="s" onBack={() => go(1)} />,
  ];

  return (
    <>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');`}</style>

      <div style={{ minHeight: "100dvh", width: "100%", display: "flex", justifyContent: "center", background: page === 0 ? GREEN_DARK : MINT_BOT, fontFamily: FONT }}>
        <div style={{ width: "100%", maxWidth: 430, minHeight: "100dvh", background: page === 0 ? GREEN_DARK : MINT_TOP, position: "relative", overflowX: "hidden", boxShadow: "0 0 60px rgba(0,0,0,0.08)" }}>
          <div key={page} style={{ animation: `slideIn 300ms ${EASE}` }}>
            {pages[page]}
          </div>
        </div>
      </div>

      <style>{`
        @keyframes slideIn { from { opacity: 0; transform: translateX(28px);} to { opacity: 1; transform: translateX(0);} }
        @keyframes bob { 0%,100% { transform: translateY(0);} 50% { transform: translateY(-11px);} }
        @keyframes sway { 0%,100% { transform: rotate(-2.5deg);} 50% { transform: rotate(2.5deg);} }
        @keyframes popBubble { from { opacity: 0; transform: translateY(8px) scale(0.9);} to { opacity: 1; transform: translateY(0) scale(1);} }
        @keyframes toastUp { from { opacity: 0; transform: translateY(10px);} to { opacity: 1; transform: translateY(0);} }
        @keyframes segShine { 0%,100% { filter: brightness(1);} 50% { filter: brightness(1.12);} }
        .caret { color: currentColor; opacity: 0.7; animation: blink 900ms step-end infinite; margin-left: 1px; }
        @keyframes blink { 0%,100% { opacity: 0.7;} 50% { opacity: 0;} }
        .cta-pulse { animation: ctaGlow 6s ease-in-out infinite; }
        @keyframes ctaGlow { 0%,84%,100% { box-shadow: 0 0 0 0 rgba(175,207,34,0);} 90% { box-shadow: 0 0 0 9px rgba(175,207,34,0.22);} 95% { box-shadow: 0 0 0 0 rgba(175,207,34,0);} }
        input::placeholder { color: #A9B7A0; }
        button:focus-visible { outline: 3px solid ${GREEN_DARK}; }
        @media (prefers-reduced-motion: reduce) {
          *, .cta-pulse, .caret { animation-duration: 0.001ms !important; animation-iteration-count: 1 !important; transition-duration: 0.001ms !important; }
        }
      `}</style>
    </>
  );
}
